```hcl
resource "aws_kms_key" "ebs_kms_key" {
  description             = "KMS key for encrypting EBS volume"
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action    = "kms:*"
        Resource  = "*"
      },
      {
        Sid       = "Allow EC2 service to use the key"
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for encrypting RDS storage"
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action    = "kms:*"
        Resource  = "*"
      },
      {
        Sid       = "Allow RDS service to use the key"
        Effect    = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_ebs_volume" "secure_data_volume" {
  availability_zone = "us-west-2a"
  size              = 50
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs_kms_key.arn
  type              = "gp3"

  tags = {
    Name        = "secure-data-volume"
    Environment = "production"
    Purpose     = "data-storage"
  }
}

resource "aws_db_instance" "mariadb_instance" {
  identifier_prefix               = "secure-mariadb-"
  engine                          = "mariadb"
  engine_version                  = "10.6.12"
  instance_class                  = "db.t3.micro"
  allocated_storage               = 20
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds_kms_key.arn
  backup_retention_period         = 30
  multi_az                        = true
  publicly_accessible             = false
  skip_final_snapshot             = true
  apply_immediately               = false
  vpc_security_group_ids          = [aws_security_group.rds_sg.id]
  db_subnet_group_name            = aws_db_subnet_group.rds_subnet_group.name
  password_length                 = 16
  username                        = "dbadmin"
  generate_password               = true
  storage_type                    = "gp2"
  enabled_cloudwatch_logs_exports = ["error"]

  tags = {
    Name        = "secure-mariadb-instance"
    Environment = "production"
    Owner       = "devops"
  }
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "secure-rds-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name        = "secure-rds-subnet-group"
    Environment = "production"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-secure-sg"
  description = "Security group for secure RDS access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "secure-rds-sg"
    Environment = "production"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "secure-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "private-b"
  }
}

data "aws_caller_identity" "current" {}

