```hcl
locals {
  environment = "prod"
  project     = "secure-postgres"
  app_name    = "postgres-db"
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name      = "${local.project}-${local.environment}-vpc"
    Project   = local.project
    Env       = local.environment
    Terraform = "true"
  }
}

resource "aws_subnet" "private" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 10)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name      = "${local.project}-${local.environment}-private-subnet-${count.index + 1}"
    Project   = local.project
    Env       = local.environment
    Terraform = "true"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "postgres" {
  name       = "${local.project}-${local.environment}-db-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name      = "${local.project}-${local.environment}-db-subnet-group"
    Project   = local.project
    Env       = local.environment
    Terraform = "true"
  }
}

resource "aws_kms_key" "postgres" {
  description             = "KMS key for encrypting PostgreSQL RDS instance"
  enable_key_rotation     = true
  deletion_window_in_days = 30

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS to use the key"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow EC2 to create grants for RDS"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action   = "kms:CreateGrant"
        Resource = "*"
        Condition = {
          Bool = {
            "kms:GrantIsForAWSResource" = "true"
          }
        }
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

resource "aws_security_group" "postgres" {
  name        = "${local.project}-${local.environment}-postgres-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name      = "${local.project}-${local.environment}-postgres-sg"
    Project   = local.project
    Env       = local.environment
    Terraform = "true"
  }
}

resource "aws_vpc_security_group_ingress_rule" "postgres_ingress" {
  security_group_id = aws_security_group.postgres.id
  cidr_ipv4         = "10.0.0.0/16"
  from_port         = 5432
  to_port           = 5432
  ip_protocol       = "tcp"
  description       = "Allow PostgreSQL access from within VPC"
}

resource "aws_vpc_security_group_egress_rule" "postgres_egress" {
  security_group_id = aws_security_group.postgres.id
  cidr_ipv4         = "0.0.0.0/0"
  from_port         = 0
  to_port           = 0
  ip_protocol       = "-1"
  description       = "Allow all outbound traffic"
}

resource "aws_db_parameter_group" "postgres" {
  name        = "${local.project}-${local.environment}-postgres-param-group"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL 15"

  parameter {
    name  = "log_statement"
    value = "all"
  }

  parameter {
    name  = "rds.log_retention_period"
    value = "1440"
  }

  tags = {
    Name      = "${local.project}-${local.environment}-postgres-param-group"
    Project   = local.project
    Env       = local.environment
    Terraform = "true"
  }
}

resource "aws_db_instance" "postgres" {
  identifier                  = "${local.project}-${local.environment}-db"
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = "db.t4g.medium"
  allocated_storage           = 50
  storage_type                = "gp3"
  db_subnet_group_name        = aws_db_subnet_group.postgres.name
  db_parameter_group_name     = aws_db_parameter_group.postgres.name
  multi_az                    = true
  publicly_accessible         = false
  allow_major_version_upgrade = false
  auto_minor_version_upgrade  = false
  backup_retention_period     = 7
  skip_final_snapshot         = true
  deletion_protection         = true
  performance_insights_enabled = true
  storage_encrypted           = true
  kms_key_id                  = aws_kms_key.postgres.arn
  vpc_security_group_ids      = [aws_security_group.postgres.id]
  username                    = var.db_username
  password                    = var.db_password
  port                        = 5432

  tags = {
    Name      = "${local.project}-${local.environment}-db-instance"
    Project   = local.project
    Env       = local.environment
    Terraform = "true"
  }
}

