```hcl
locals {
  environment = "prod"
  project     = "secure-stack"
  tags = {
    Environment = local.environment
    Project     = local.project
    ManagedBy   = "Terraform"
  }
}

# VPC with secure configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  instance_tenancy     = "default"

  tags = merge(local.tags, {
    Name = "${local.project}-vpc"
  })
}

# KMS Key for EBS encryption with annual rotation enabled
resource "aws_kms_key" "ebs_kms_key" {
  description             = "KMS key for encrypting EBS volumes"
  enable_key_rotation     = true
  key_usage               = "ENCRYPT_DECRYPT"
  customer_master_key_spec = "SYMMETRIC_DEFAULT"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = [
          "kms:*"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow EC2 Service to use the KMS key"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action   = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = merge(local.tags, {
    Name = "${local.project}-ebs-kms-key"
  })
}

# EBS Volume encrypted with customer-managed KMS key
resource "aws_ebs_volume" "data_volume" {
  availability_zone = "us-west-2a"
  size              = 100
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs_kms_key.arn

  tags = merge(local.tags, {
    Name = "${local.project}-data-volume"
  })
}

# SNS Topic for alerts, encrypted with KMS
resource "aws_kms_key" "sns_kms_key" {
  description         = "KMS key for encrypting SNS topic"
  enable_key_rotation = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = [
          "kms:*"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow SNS to encrypt/decrypt"
        Effect = "Allow"
        Principal = {
          Service = "sns.amazonaws.com"
        }
        Action   = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = merge(local.tags, {
    Name = "${local.project}-sns-kms-key"
  })
}

resource "aws_sns_topic" "alerts" {
  name                        = "${local.project}-alerts-topic"
  kms_master_key_id           = aws_kms_key.sns_kms_key.arn
  fifo_topic                  = false
  content_based_deduplication = false

  tags = local.tags
}

# SQS Queue for alerts, encrypted with KMS
resource "aws_kms_key" "sqs_kms_key" {
  description         = "KMS key for encrypting SQS queue"
  enable_key_rotation = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = [
          "kms:*"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow SQS to encrypt/decrypt"
        Effect = "Allow"
        Principal = {
          Service = "sqs.amazonaws.com"
        }
        Action   = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = merge(local.tags, {
    Name = "${local.project}-sqs-kms-key"
  })
}

resource "aws_sqs_queue" "alerts_queue" {
  name                       = "${local.project}-alerts-queue.fifo"
  fifo_queue                 = true
  content_based_deduplication = true
  kms_master_key_id          = aws_kms_key.sqs_kms_key.arn
  tags                       = local.tags
}

# VPC Flow Logs to capture network traffic
resource "aws_flow_log" "vpc_flow_log" {
  log_destination_type = "cloud-watch-logs"
  log_group_name       = "/aws/vpc/flowlogs/${aws_vpc.main.id}"
  traffic_type         = "ALL"
  vpc_id               = aws_vpc.main.id

  tags = merge(local.tags, {
    Name = "${local.project}-flow-log"
  })
}

# Data source to get current AWS account ID for IAM policies
data "aws_caller_identity" "current" {}

