resource "aws_kms_key" "log_encryption_key" {
  description             = "KMS key for encrypting logs with annual key rotation"
  enable_key_rotation     = true
  key_usage               = "ENCRYPT_DECRYPT"
  customer_master_key_spec = "SYMMETRIC_DEFAULT"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
