    Name        = "${local.app_name}-data-volume"
    Environment = local.environment
    Project     = local.project
  }
}

# Lambda Function with execution role (not shown, but assumed to be passed via assume_role_policy elsewhere)
# We define the log group explicitly for retention and permissions control
resource "aws_cloudwatch_log_group" "lambda_log_group" {
  name              = "/aws/lambda/${aws_lambda_function.app_lambda.function_name}"
  retention_in_days = 30
  kms_key_id        = aws_kms_key.lambda_kms_key.arn

  tags = {
    Name        = "${local.app_name}-lambda-logs"
    Environment = local.environment
    Project     = local.project
  }
}

# KMS Key for Lambda log encryption
resource "aws_kms_key" "lambda_kms_key" {
  description             = "KMS key for encrypting Lambda CloudWatch logs"
  enable_key_rotation     = true
  key_usage               = "ENCRYPT_DECRYPT"
  customer_master_key_spec = "SYMMETRIC_DEFAULT"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow CloudWatch Logs to encrypt logs"
        Effect = "Allow"
        Principal = {
          Service = "logs.us-west-2.amazonaws.com"
        }
        Action = [
          "kms:Encrypt*",
          "kms:Decrypt*",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:Describe*"
        ]
        Resource = "*"
      }
    ]
  })
}

# Lambda function (code assumed to be in S3 or local file outside scope)
resource "aws_lambda_function" "app_lambda" {
  filename         = "lambda-function.zip"
  function_name    = "${local.app_name}-app-lambda"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("lambda-function.zip")

  environment {
    variables = {
      LOG_LEVEL = "INFO"
    }
  }

  # Ensure logs go to the dedicated log group
  depends_on = [aws_cloudwatch_log_group.lambda_log_group]

  tags = {
    Name        = "${local.app_name}-lambda"
    Environment = local.environment
    Project     = local.project
  }
}

# IAM role for Lambda (required, minimal permissions)
resource "aws_iam_role" "lambda_role" {
  name = "${local.app_name}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# MariaDB RDS Instance - not publicly accessible, encrypted, backup retention
resource "aws_db_instance" "mariadb_instance" {
  identifier_prefix            = "${local.app_name}-mariadb-"
  engine                       = "mariadb"
  engine_version               = "10.6.12"
  instance_class               = "db.t3.micro"
  allocated_storage            = 20
  storage_encrypted            = true
  kms_key_id                   = aws_kms_key.rds_kms_key.arn
  backup_retention_period      = 30
  multi_az                     = true
  publicly_accessible          = false
  skip_final_snapshot          = true
  vpc_security_group_ids       = [aws_security_group.rds_sg.id]
  db_subnet_group_name         = aws_db_subnet_group.rds_subnet_group.name
  deletion_protection          = true
  password_length              = 16
  username                     = "dbadmin"
  generate_db_auth_token        = false
  manage_master_user_password   = true

  tags = {
    Name        = "${local.app_name}-mariadb"
    Environment = local.environment
    Project     = local.project
  }
}

# Subnet group for RDS (assumes private subnets exist)
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "${local.app_name}-rds-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with actual private subnets

  tags = {
    Name        = "${local.app_name}-rds-subnet-group"
    Environment = local.environment
    Project     = local.project
  }
}

# Security group for RDS (least privilege - lock down ports)
resource "aws_security_group" "rds_sg" {
  name        = "${local.app_name}-rds-sg"
  description = "Security group for MariaDB RDS instance"
  vpc_id      = "vpc-12345678" # Replace with actual VPC ID

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to internal VPC or specific app subnets
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "${local.app_name}-rds-sg"
    Environment = local.environment
    Project     = local.project
  }
}

