```hcl
locals {
  common_tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
    Project     = "secure-web-stack"
  }
}

# KMS Key for encrypting logs and other services
resource "aws_kms_key" "log_encryption_key" {
  description             = "KMS key for encrypting logs and secure data at rest"
  enable_key_rotation     = true
  enabled                 = true
  deletion_window_in_days = 30

  tags = merge(local_tags, { Name = "log-encryption-key" })

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = { AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root" }
        Action    = "kms:*"
        Resource  = "*"
      },
      {
        Sid       = "Allow SNS to encrypt/decrypt"
        Effect    = "Allow"
        Principal = { Service = "sns.amazonaws.com" }
        Action = [
          "kms:GenerateDataKey*",
          "kms:Decrypt"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = "${data.aws_caller_identity.current.account_id}"
          }
          ArnLike = {
            "aws:SourceArn" = aws_sns_topic.alerts.arn
          }
        }
      },
      {
        Sid       = "Allow SQS to encrypt/decrypt"
        Effect    = "Allow"
        Principal = { Service = "sqs.amazonaws.com" }
        Action = [
          "kms:GenerateDataKey*",
          "kms:Decrypt"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = "${data.aws_caller_identity.current.account_id}"
          }
          ArnLike = {
            "aws:SourceArn" = aws_sqs_queue.alerts_queue.arn
          }
        }
      },
      {
        Sid       = "Allow DynamoDB to encrypt/decrypt"
        Effect    = "Allow"
        Principal = { Service = "dynamodb.amazonaws.com" }
        Action = [
          "kms:GenerateDataKey*",
          "kms:Decrypt"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = "${data.aws_caller_identity.current.account_id}"
          }
          ArnLike = {
            "aws:SourceArn" = aws_dynamodb_table.events.arn
          }
        }
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# SNS Topic for alerts, encrypted with KMS
resource "aws_sns_topic" "alerts" {
  name                        = "alerts-topic"
  kms_master_key_id           = aws_kms_key.log_encryption_key.arn
  delivery_policy             = jsonencode({
    http = {
      defaultHealthyRetryPolicy = {
        minDelayTarget = 20
        maxDelayTarget = 20
        numRetries     = 3
        numMaxDelayRetries = 0
        backoffFunction = "linear"
      }
      disableSubscriptionOverrides = false
    }
  })
  tags                        = local_tags
}

# SQS Queue for alerts, encrypted with KMS
resource "aws_sqs_queue" "alerts_queue" {
  name                       = "alerts-queue"
  kms_master_key_id          = aws_kms_key.log_encryption_key.arn
  kms_data_key_reuse_period_seconds = 300
  tags                       = local_tags
}

# Security Group for EC2 instance
resource "aws_security_group" "web_server_sg" {
  name        = "web-server-sg"
  description = "Allow HTTPS from anywhere, SSH only from 10.0.0.0/8"
  tags        = local_tags

  # Allow HTTPS (8443) from anywhere
  ingress {
    from_port   = 8443
    to_port     = 8443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH (22) only from 10.0.0.0/8
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    ignore_changes = [tags]
  }
}

# EC2 Instance with encrypted root volume and IMDSv2
resource "aws_instance" "web_server" {
  ami                    = "ami-0c02fb55956c7d316" # Example: Amazon Linux 2 in us-east-1
  instance_type          = "t3.micro"
  vpc_security_group_ids = [aws_security_group.web_server_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.web_server_profile.name
  metadata_options {
    http_endpoint               = "enabled"
    http_tokens                 = "required"  # Enforces IMDSv2
    http_put_response_hop_limit = 2
  }

  root_block_device {
    volume_type = "gp3"
    volume_size = 20
    encrypted   = true
  }

  tags = merge(local_tags, { Name = "web-server" })
}

# IAM Role and Instance Profile for EC2 (least privilege)
resource "aws_iam_role" "web_server_role" {
  name = "web-server-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = local_tags
}

resource "aws_iam_instance_profile" "web_server_profile" {
  name = "web-server-instance-profile"
  role = aws_iam_role.web_server_role.name
}

# DynamoDB Table with encryption and on-demand billing
resource "aws_dynamodb_table" "events" {
  name         = "events"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "event_id"

  attribute {
    name = "event_id"
    type = "S"
  }

  server_side_encryption {
    enabled     = true
    kms_key_arn = aws_kms_key.log_encryption_key.arn
  }

  tags = local_tags
}

