resource "aws_kms_key" "backup_key" {
  description             = "KMS key for encrypting EC2 root volume and backups"
  enable_key_rotation     = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action    = [
          "kms:*"
        ]
        Resource  = "*"
      },
      {
        Sid       = "Allow EC2 service to use the key"
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action    = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_security_group" "web_server_sg" {
  name        = "web-server-secure-sg"
  description = "Allow HTTPS from anywhere, SSH only from 10.0.0.0/8"
  vpc_id      = var.vpc_id

  # Allow HTTPS (port 8443) from anywhere
  ingress {
    from_port   = 8443
    to_port     = 8443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH (port 22) only from 10.0.0.0/8
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "web-server-sg"
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
}

resource "aws_instance" "web_server" {
  ami                    = var.ami_id
  instance_type          = var.instance_type
  subnet_id              = var.subnet_id
  vpc_security_group_ids = [aws_security_group.web_server_sg.id]
  iam_instance_profile   = var.iam_instance_profile

  # Use encrypted root volume with KMS key
  root_block_device {
    encrypted           = true
    kms_key_id          = aws_kms_key.backup_key.arn
    volume_size         = 20
    volume_type         = "gp3"
    delete_on_termination = true
  }

  # Require IMDSv2
  metadata_options {
    http_endpoint               = "enabled"
    http_tokens                 = "required"
    http_put_response_hop_limit = 2
    instance_metadata_tags      = "disabled"
  }

  tags = {
    Name        = "web-server-instance"
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
}

