locals {
  environment = "production"
  project     = "secure-stack"
  tags = {
    Environment = local.environment
    Project     = local.project
    ManagedBy   = "Terraform"
  }
}

# KMS Key for EBS encryption with annual rotation and strict key policy
resource "aws_kms_key" "ebs_kms" {
  description             = "KMS key for encrypting EBS volumes"
  enable_key_rotation     = true
  customer_master_key_spec = "SYMMETRIC_DEFAULT"
  key_usage                = "ENCRYPT_DECRYPT"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = [
          "kms:*"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow EC2 service to use the key"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action   = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid    = "Allow attachment of persistent resources"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action   = "kms:CreateGrant"
        Resource = "*"
        Condition = {
          Bool = {
            "kms:GrantIsForAWSResource" = "true"
          }
        }
      }
    ]
  })

  tags = merge(local.tags, { Name = "${local.project}-ebs-kms" })
}

# EBS Volume encrypted with customer-managed KMS key
resource "aws_ebs_volume" "data_volume" {
  availability_zone = "us-west-2a"
  size              = 50
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs_kms.arn
  type              = "gp3"

  tags = merge(local.tags, { Name = "${local.project}-data-volume" })
}

