          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = merge(local.tags, { Name = "${local.project}-rds-kms" })
}

# Secure Postgres RDS instance
resource "aws_db_instance" "postgres" {
  identifier_prefix              = "${local.project}-postgres-"
  engine                         = "postgres"
  engine_version                 = "15.4"
  instance_class                 = "db.t3.micro"
