```hcl
locals {
  environment = "production"
  project     = "secure-infra"
  tags = {
    Environment = local.environment
    Project     = local.project
    ManagedBy   = "Terraform"
  }
}

# KMS Key with strict key policy for encryption at rest
resource "aws_kms_key" "main" {
  description             = "KMS key for encrypting production resources"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  tags = merge(local.tags, {
    Name = "${local.project}-kms-key"
  })

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action    = [
          "kms:*"
        ]
        Resource  = "*"
      },
      {
        Sid       = "Allow EC2 to use the key"
        Effect    = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# Placement group for low-latency, high-throughput instance clustering
resource "aws_placement_group" "pg" {
  name     = "${local.project}-placement-group"
  strategy = "cluster"

  tags = merge(local.tags, {
    Name = "${local.project}-placement-group"
  })
}

# Network interface with private IP, no public access, encrypted via KMS
resource "aws_network_interface" "secure_nic" {
  subnet_id       = aws_subnet.private.id
  private_ips     = ["10.0.1.10"]
  security_groups = [aws_security_group.internal.id]

  tags = merge(local.tags, {
    Name = "${local.project}-secure-nic"
  })
}

# Capacity reservation to ensure instance capacity in production
resource "aws_ec2_capacity_reservation" "prod" {
  availability_zone      = aws_subnet.private.availability_zone
  instance_type          = "t3.medium"
  instance_platform      = "Linux/UNIX"
  instance_count         = 2
  ebs_optimized          = true
  tenancy                = "default"
  ephemeral_storage      = false
  outpost_arn            = ""
  # Use KMS key for encryption of EBS volumes
  encrypted              = true
  kms_key_id             = aws_kms_key.main.arn

  tags = merge(local.tags, {
    Name = "${local.project}-capacity-reservation"
  })
}

# Assume private subnet and security group exist; defined here for completeness in context
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = merge(local.tags, {
    Name = "${local.project}-vpc"
  })
}

resource "aws_subnet" "private" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = false

  tags = merge(local.tags, {
    Name = "${local.project}-private-subnet"
  })
}

resource "aws_security_group" "internal" {
  name   = "${local.project}-internal-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge(local.tags, {
    Name = "${local.project}-internal-sg"
  })
}

data "aws_availability_zones" "available" {
  state = "available"
}

