```hcl
locals {
  environment = "production"
  project     = "orders-processing"
  owner       = "devops-team"
}

# KMS Key for encryption with annual rotation and explicit key policy
resource "aws_kms_key" "backup_key" {
  description             = "KMS key for encrypting SQS and SNS resources"
  enable_key_rotation     = true
  rotation_rules {
    automatically_after_days = 365
  }

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action    = "kms:*"
        Resource  = "*"
      },
      {
        Sid       = "Allow SNS to encrypt messages"
        Effect    = "Allow"
        Principal = {
          Service = "sns.amazonaws.com"
        }
        Action    = [
          "kms:GenerateDataKey",
          "kms:Decrypt"
        ]
        Resource  = "*"
        Condition = {
          ArnEquals = {
            "kms:ViaService" = "arn:aws:sns:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:orders-topic"
          }
        }
      },
      {
        Sid       = "Allow SQS to encrypt messages"
        Effect    = "Allow"
        Principal = {
          Service = "sqs.amazonaws.com"
        }
        Action    = [
          "kms:GenerateDataKey",
          "kms:Decrypt"
        ]
        Resource  = "*"
        Condition = {
          ArnEquals = {
            "kms:ViaService" = "arn:aws:sqs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:orders-queue"
          }
        }
      }
    ]
  })

  tags = {
    Name        = "${local.project}-kms-key"
    Environment = local.environment
    Project     = local.project
    Owner       = local.owner
  }
}

# SNS Topic for order events, encrypted with KMS
resource "aws_sns_topic" "orders" {
  name = "orders-topic"

  kms_master_key_id = aws_kms_key.backup_key.arn

  tags = {
    Name        = "orders-topic"
    Environment = local.environment
    Project     = local.project
    Owner       = local.owner
  }
}

# SQS Queue for order events, encrypted with KMS
resource "aws_sqs_queue" "orders" {
  name                              = "orders-queue"
  kms_master_key_id                 = aws_kms_key.backup_key.arn
  kms_data_key_reuse_period_seconds = 300

  # Prevent public access
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Allow-SQS-Send-Receive-From-Own-Account"
        Effect    = "Allow"
        Principal = "*"
        Action    = [
          "sqs:SendMessage",
          "sqs:ReceiveMessage",
          "sqs:DeleteMessage",
          "sqs:GetQueueAttributes"
        ]
        Resource  = aws_sqs_queue.orders.arn
        Condition = {
          StringEquals = {
            "AWS:SourceOwner" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })

  tags = {
    Name        = "orders-queue"
    Environment = local.environment
    Project     = local.project
    Owner       = local.owner
  }
}

# IAM Role for application processing orders
resource "aws_iam_role" "orders_processor" {
  name = "orders-processor-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = {
    Environment = local.environment
    Project     = local.project
    Owner       = local.owner
  }
}

# IAM Policy granting least privilege: only sqs:ReceiveMessage on the specific queue
resource "aws_iam_role_policy" "orders_processor_policy" {
  name = "orders-processor-policy"
  role = aws_iam_role.orders_processor.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "ProcessOrdersFromQueue"
        Effect = "Allow"
        Action = "sqs:ReceiveMessage"
        Resource = aws_sqs_queue.orders.arn
