# Security group for the EC2 instance
resource "aws_security_group" "web_server_sg" {
  name        = "web-server-secure-sg"
  description = "Allow HTTPS from anywhere, SSH only from 10.0.0.0/8"
  tags = merge(local.common_tags, {
    Name = "web-server-sg"
  })

  # Allow HTTPS from anywhere
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH only from 10.0.0.0/8
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  # Allow outbound all
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = local.common_tags
