resource "aws_security_group" "web_sg" {
  name        = "web-server-sg"
  description = "Allow HTTPS from anywhere and SSH from private subnet only"
  tags = merge(local.common_tags, {
    Name = "web-server-security-group"
  })

  # Allow HTTPS (443) from anywhere
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH (22) only from 192.168.0.0/16
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["192.168.0.0/16"]
  }

  # Allow outbound all
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  lifecycle {
    ignore_changes = [tags] # Prevent external tag changes from drift
  }
}

# EC2 instance with encrypted root volume and IMDSv2 enforced
