# KMS Key for encrypting secrets and parameters
resource "aws_kms_key" "secrets_kms_key" {
  description             = "KMS key for encrypting Secrets Manager secrets and SSM parameters in production"
  enable_key_rotation     = true
  isEnabled               = true
  deletion_window_in_days = 30

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action = [
          "kms:Create*",
          "kms:Describe*",
          "kms:Enable*",
          "kms:List*",
          "kms:Put*",
          "kms:Update*",
          "kms:Revoke*",
          "kms:Disable*",
          "kms:Get*",
          "kms:Delete*",
          "kms:ScheduleKeyDeletion",
          "kms:CancelKeyDeletion",
          "kms:GenerateDataKey",
          "kms:TagResource",
          "kms:UntagResource"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "kms:CallerAccount" = "${data.aws_caller_identity.current.account_id}"
            "kms:ViaService" = [
              "secretsmanager.${data.aws_region.current.name}.amazonaws.com",
              "ssm.${data.aws_region.current.name}.amazonaws.com"
            ]
          }
        }
      }
    ]
  })

  tags = merge(local.tags, { Name = "${local.project}-secrets-kms-key" })
}

data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

# IAM Policy granting least privilege access to Secrets Manager and SSM using KMS
resource "aws_iam_policy" "secrets_access_policy" {
  name        = "${local.project}-secrets-access-policy"
  description = "Grants minimal access to Secrets Manager and SSM parameters with KMS encryption"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = aws_secretsmanager_secret.app_secret.arn
      },
      {
        Effect = "Allow"
        Action = [
          "ssm:GetParameter",
          "ssm:DescribeParameters"
        ]
        Resource = aws_ssm_parameter.app_config_parameter.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = aws_kms_key.secrets_kms_key.arn
      }
    ]
  })

  tags = local.tags
}

# Secrets Manager Secret (without storing actual secret value here)
