  kms_key_id  = aws_kms_key.secrets_kms_key.arn

  tags = local.tags
}

# Secrets Manager Secret Version - expects secret to be passed via secure input (e.g., TF_VAR or CI secret)
resource "aws_secretsmanager_secret_version" "app_secret_version" {
  secret_id     = aws_secretsmanager_secret.app_secret.id
  secret_string = var.application_secret_json # Must be provided securely at runtime

  depends_on = [aws_secretsmanager_secret.app_secret]
}

# SSM Parameter (secure string) for configuration
resource "aws_ssm_parameter" "app_config_parameter" {
  name        = "/prod/${local.project}/config/database-url"
  type        = "SecureString"
  value       = var.database_url # Provided securely at runtime
  description = "Encrypted database URL for production application"
  key_id      = aws_kms_key.secrets_kms_key.arn

  tags = local.tags
}

