        ]
        Resource = "*"
        Condition = {
          Bool = {
            "kms:GrantIsForAWSResource" = "true"
          }
        }
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# Security group for EC2 web server
resource "aws_security_group" "web_server_sg" {
  name        = "secure-web-server-sg"
  description = "Allow HTTPS from anywhere, SSH only from private IP range"
  tags        = local.common_tags

  # Allow HTTPS (443) from anywhere
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH (22) only from 172.16.0.0/12 (RFC 1918 private range)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["172.16.0.0/12"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Restrict ingress from public internet beyond defined rules
  lifecycle {
    ignore_changes = [revoke_rules_on_delete]
  }
}

# Encrypted EBS data volume using KMS key
resource "aws_ebs_volume" "data_volume" {
  availability_zone = "us-west-2a"
  size              = 200
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs_kms_key.arn
  type              = "gp3"
  tags              = merge(local.common_tags, { Name = "secure-data-volume" })
}

# EC2 web server with encrypted root volume and IMDSv2 required
resource "aws_instance" "web_server" {
  ami                    = "ami-0abcdef1234567890" # Example AMI; use latest Amazon Linux 2 or Ubuntu LTS
  instance_type          = "t3.medium"
  availability_zone      = "us-west-2a"
  vpc_security_group_ids = [aws_security_group.web_server_sg.id]
  tags                   = merge(local.common_tags, { Name = "secure-web-server" })

  # Use encrypted root volume
  root_block_device {
    volume_type = "gp3"
    volume_size = 50
    encrypted   = true
  }

  # Metadata options: require IMDSv2 and disable access to sensitive data
  metadata_options {
    http_endpoint               = "enabled"
    http_tokens                 = "required"
    http_put_response_hop_limit = 2
    instance_metadata_tags      = "disabled"
  }

  # Ensure no public IP is assigned; use NAT or Load Balancer for public access
  associate_public_ip_address = false

  # User data can be added here securely via SSM or config management
  # user_data_replace_on_change = true
}

