}

# Security Group for EC2 Instance
resource "aws_security_group" "web_server_sg" {
  name        = "web-server-secure-sg"
  description = "Allow HTTPS from anywhere, SSH only from 172.16.0.0/12"

  tags = local.common_tags
}

resource "aws_security_group_rule" "allow_https_inbound" {
  type              = "ingress"
  security_group_id = aws_security_group.web_server_sg.id
  protocol          = "tcp"
  from_port         = 443
  to_port           = 443
  cidr_blocks       = ["0.0.0.0/0"]
}

resource "aws_security_group_rule" "allow_ssh_inbound" {
  type              = "ingress"
  security_group_id = aws_security_group.web_server_sg.id
  protocol          = "tcp"
  from_port         = 22
  to_port           = 22
  cidr_blocks       = ["172.16.0.0/12"]
}

resource "aws_security_group_rule" "allow_all_outbound" {
  type              = "egress"
  security_group_id = aws_security_group.web_server_sg.id
  protocol          = "-1"
  from_port         = 0
  to_port           = 0
  cidr_blocks       = ["0.0.0.0/0"]
}

# EC2 Instance with encrypted root volume and IMDSv2 required
resource "aws_instance" "web_server" {
  ami                    = "ami-0abcdef1234567890" # Replace via SSM lookup in real use
  instance_type          = "t3.medium"
  vpc_security_group_ids = [aws_security_group.web_server_sg.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name
  metadata_options {
    http_endpoint               = "enabled"
    http_tokens                 = "required"  # Enforce IMDSv2
    http_put_response_hop_limit = 2
  }

  root_block_device {
    volume_size = 30
    volume_type = "gp3"
    encrypted   = true
  }

  tags = merge(local.common_tags, {
    Name = "secure-web-server"
  })
}

# IAM Role for EC2 Instance (least privilege)
resource "aws_iam_role" "ec2_role" {
  name = "ec2-instance-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-instance-profile"
  role = aws_iam_role.ec2_role.name
}

# EBS Data Volume (200GB, encrypted with customer-managed KMS key)
resource "aws_ebs_volume" "data_volume" {
  availability_zone = aws_instance.web_server.availability_zone
  size              = 200
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs_kms_key.arn
  type              = "gp3"

  tags = merge(local.common_tags, {
    Name = "encrypted-data-volume"
