data "aws_caller_identity" "current" {}

# Secure EBS Volume (200GB) encrypted with customer-managed KMS key
resource "aws_ebs_volume" "data_volume" {
  availability_zone = "us-west-2a"
  size              = 200
  encrypted         = true
  kms_key_id        = aws_kms_key.secure_key.arn
  type              = "gp3"

  tags = merge(local.common_tags, {
    Name = "secure-data-volume"
  })
}

# Private S3 Bucket for static assets with KMS encryption, versioning, and no public access
resource "aws_s3_bucket" "static_assets" {
  bucket = "secure-static-assets-${data.aws_caller_identity.current.account_id}"

  tags = local.common_tags
}

resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.static_assets.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.static_assets.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.secure_key.arn
    }
  }
