```hcl
locals {
  common_tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
    Project     = "secure-billing-stack"
  }
}

# KMS Key for EBS encryption with annual rotation and explicit key policy
resource "aws_kms_key" "ebs_kms_key" {
  description             = "KMS key for encrypting EBS volumes"
  enable_key_rotation     = true
  customer_master_key_spec = "SYMMETRIC_DEFAULT"
  key_usage                = "ENCRYPT_DECRYPT"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = { AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root" }
        Action    = "kms:*"
        Resource  = "*"
      },
      {
        Sid       = "Allow EC2 service to use the key"
        Effect    = "Allow"
        Principal = { Service = "ec2.amazonaws.com" }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = merge(local.common_tags, { Name = "ebs-encryption-key" })
}

# KMS Key for SNS/SQS encryption (used for both)
resource "aws_kms_key" "messaging_kms_key" {
  description         = "KMS key for encrypting SNS and SQS"
  enable_key_rotation = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Enable IAM User Permissions"
        Effect    = "Allow"
        Principal = { AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root" }
        Action    = "kms:*"
        Resource  = "*"
      },
      {
        Sid       = "Allow SNS to encrypt/decrypt"
        Effect    = "Allow"
        Principal = { Service = "sns.amazonaws.com" }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Sid       = "Allow SQS to encrypt/decrypt"
        Effect    = "Allow"
        Principal = { Service = "sqs.amazonaws.com" }
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })

  tags = merge(local.common_tags, { Name = "messaging-encryption-key" })
}

# RDS MySQL instance - not publicly accessible, encrypted, with backups
resource "aws_db_instance" "mysql_instance" {
  identifier              = "secure-mysql-instance"
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  storage_encrypted       = true
  kms_key_id              = aws_kms_key.ebs_kms_key.arn
  backup_retention_period = 30
  skip_final_snapshot     = true
  deletion_protection     = false
  publicly_accessible     = false
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.rds_subnet_group.name

  username = "admin"
  password = random_password.db_password.result

  tags = merge(local.common_tags, { Name = "secure-mysql" })
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = var.subnet_ids

  tags = merge(local.common_tags, { Name = "rds-subnet-group" })
}

resource "aws_security_group" "rds_sg" {
  name   = "rds-secure-sg"
  vpc_id = var.vpc_id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = merge(local.common_tags, { Name = "rds-security-group" })
}

# Encrypted SQS Queue for billing events
resource "aws_sqs_queue" "billing_queue" {
  name                       = "billing-events-queue"
  kms_master_key_id          = aws_kms_key.messaging_kms_key.arn
  server_side_encryption_enabled = true
  visibility_timeout_seconds = 300
  message_retention_seconds  = 86400

  tags = merge(local.common_tags, { Name = "billing-sqs-queue" })
}

# Encrypted SNS Topic for billing events
resource "aws_sns_topic" "billing_topic" {
  name                        = "billing-events-topic"
  kms_master_key_id           = aws_kms_key.messaging_kms_key.arn
  fifo_topic                  = false
  content_based_deduplication = false

  tags = merge(local.common_tags, { Name = "billing-sns-topic" })
}

# EBS Volume - 100GB, encrypted with customer-managed KMS key
resource "aws_ebs_volume" "data_volume" {
  availability_zone = var.availability_zone
  size              = 100
  encrypted         = true
  kms_key_id        = aws_kms_key.ebs_kms_key.arn

  tags = merge(local.common_tags, { Name = "encrypted-data-volume" })
}

# DynamoDB Table 'cart' with encryption and on-demand capacity
resource "aws_dynamodb_table" "cart_table" {
  name         = "cart"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "user_id"
  range_key    = "item_id"

  attribute {
    name = "user_id"
    type = "S"
  }

  attribute {
    name = "item_id"
    type = "S"
  }

  server_side_encryption {
    enabled     = true
    kms_key_arn = aws_kms_key.ebs_kms_key.arn
  }

  tags = merge(local.common_tags, { Name = "shopping-cart-table" })
}

# Random password for RDS to avoid hardcoded secrets
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Data sources
